import api from './api';

const CMS_API_BASE = '/admin';

// Generic fetch wrapper that returns null on any error (500, 404, etc)
async function safeFetch(promise) {
  try {
    const response = await promise;
    return response.data;
  } catch (e) {
    // Silently return null for any error - this allows fallback to static content
    console.log('API not available:', e.message);
    return null;
  }
}

export const cmsService = {
  // Get all pages
  async getPages() {
    try {
      const response = await api.get(`${CMS_API_BASE}/pages`);
      return response.data;
    } catch (e) {
      console.log('CMS not available, using default content');
      return [];
    }
  },

  // Get page with sections and cards
  async getPageWithSections(pageId) {
    try {
      const response = await api.get(`${CMS_API_BASE}/pages/${pageId}`);
      return response.data;
    } catch (e) {
      return null;
    }
  },

  // Get published page by slug
  async getPublicPage(slug) {
    try {
      const response = await api.get(`/pages/${slug}`);
      return response.data;
    } catch (e) {
      return null;
    }
  },

  // Get all published pages content
  async getAllPublishedContent() {
    try {
      const response = await api.get(`${CMS_API_BASE}/pages`);
      return response.data.filter(p => p.isPublished);
    } catch (e) {
      return [];
    }
  },

  // Admin: Create page
  async createPage(data) {
    const response = await api.post(`${CMS_API_BASE}/pages`, data);
    return response.data;
  },

  // Admin: Update page
  async updatePage(id, data) {
    const response = await api.put(`${CMS_API_BASE}/pages/${id}`, data);
    return response.data;
  },

  // Admin: Delete page
  async deletePage(id) {
    const response = await api.delete(`${CMS_API_BASE}/pages/${id}`);
    return response.data;
  },

  // Admin: Create section
  async createSection(pageId, data) {
    const response = await api.post(`${CMS_API_BASE}/pages/${pageId}/sections`, data);
    return response.data;
  },

  // Admin: Update section
  async updateSection(id, data) {
    const response = await api.put(`${CMS_API_BASE}/sections/${id}`, data);
    return response.data;
  },

  // Admin: Delete section
  async deleteSection(id) {
    const response = await api.delete(`${CMS_API_BASE}/sections/${id}`);
    return response.data;
  },

  // Admin: Create card
  async createCard(sectionId, data) {
    const response = await api.post(`${CMS_API_BASE}/sections/${sectionId}/cards`, data);
    return response.data;
  },

  // Admin: Update card
  async updateCard(id, data) {
    const response = await api.put(`${CMS_API_BASE}/cards/${id}`, data);
    return response.data;
  },

  // Admin: Delete card
  async deleteCard(id) {
    const response = await api.delete(`${CMS_API_BASE}/cards/${id}`);
    return response.data;
  },

  // Admin: Reorder sections
  async reorderSections(sectionIds) {
    const response = await api.post(`${CMS_API_BASE}/sections/reorder`, { sectionIds });
    return response.data;
  },

  // Admin: Upload media
  async uploadMedia(file) {
    const formData = new FormData();
    formData.append('file', file);
    const response = await api.post(`${CMS_API_BASE}/upload`, formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });
    return response.data;
  }
};

export const contentService = {
  // ========== SERVICES (Public) ==========
  async getServices() {
    return safeFetch(api.get('/services'));
  },

  // ========== ADMIN SERVICES ==========
  async getAdminServices() {
    return safeFetch(api.get('/admin/services'));
  },

  async createService(data) {
    try {
      const response = await api.post('/admin/services', data);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to create service');
    }
  },

  async updateService(id, data) {
    try {
      const response = await api.put(`/admin/services/${id}`, data);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to update service');
    }
  },

  async deleteService(id) {
    try {
      const response = await api.delete(`/admin/services/${id}`);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to delete service');
    }
  },

  // ========== FAQS (Public) ==========
  async getFaqs() {
    return safeFetch(api.get('/faqs'));
  },

  // ========== ADMIN FAQS ==========
  async getAdminFaqs() {
    return safeFetch(api.get('/admin/faqs'));
  },

  async createFaq(data) {
    try {
      const response = await api.post('/admin/faqs', data);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to create FAQ');
    }
  },

  async updateFaq(id, data) {
    try {
      const response = await api.put(`/admin/faqs/${id}`, data);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to update FAQ');
    }
  },

  async deleteFaq(id) {
    try {
      const response = await api.delete(`/admin/faqs/${id}`);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to delete FAQ');
    }
  },

  // ========== OFFERS (Public) ==========
  async getOffers() {
    return safeFetch(api.get('/offers'));
  },

  // ========== ADMIN OFFERS ==========
  async getAdminOffers() {
    return safeFetch(api.get('/admin/offers'));
  },

  async createOffer(data) {
    try {
      const response = await api.post('/admin/offers', data);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to create offer');
    }
  },

  async updateOffer(id, data) {
    try {
      const response = await api.put(`/admin/offers/${id}`, data);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to update offer');
    }
  },

  async deleteOffer(id) {
    try {
      const response = await api.delete(`/admin/offers/${id}`);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to delete offer');
    }
  },

  // ========== TESTIMONIALS (Public) ==========
  async getTestimonials() {
    return safeFetch(api.get('/testimonials'));
  },

  // ========== ADMIN TESTIMONIALS ==========
  async getAdminTestimonials() {
    return safeFetch(api.get('/admin/testimonials'));
  },

  async createTestimonial(data) {
    try {
      const response = await api.post('/admin/testimonials', data);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to create testimonial');
    }
  },

  async updateTestimonial(id, data) {
    try {
      const response = await api.put(`/admin/testimonials/${id}`, data);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to update testimonial');
    }
  },

  async deleteTestimonial(id) {
    try {
      const response = await api.delete(`/admin/testimonials/${id}`);
      return response.data;
    } catch (e) {
      throw new Error(e.response?.data?.error || 'Failed to delete testimonial');
    }
  }
};

export default cmsService;
